import{_ as a,c as e,o as i,a as l}from"./app.09261a68.js";const f=JSON.parse('{"title":"Golang编码规范","description":"","frontmatter":{"date":"2022-09-29T00:00:00.000Z"},"headers":[],"relativePath":"zh/coding/golang/standards.md"}'),t={name:"zh/coding/golang/standards.md"},p=l('<h1 id="golang编码规范" tabindex="-1">Golang编码规范 <a class="header-anchor" href="#golang编码规范" aria-hidden="true">#</a></h1><ol><li><p>单个方法代码量不超过50行；</p></li><li><p>单个方法的传入参数不超过5个；</p></li><li><p>单个方法实现单一功能，具体功能细节需要单独封装；</p></li><li><p>方法中可以有else if,但是尽量不要有else；</p></li><li><p>单个方法中if，for之类的嵌套层数尽量不要超过3个；</p></li><li><p>不要把方法返回的变量定义在返回体声明里；</p></li><li><p>不要有魔鬼字符，尽可能用变量进行声明；</p></li><li><p>导致单个任务终结的错误返回需要添加错误日志，在重要资源的create/update/delete操作完成时需要加日志；</p></li><li><p>单个go文件中资源定义由上至下顺序： const,type,var,func;</p></li><li><p>import声明顺序： golang包，其他项目包，本项目包，三类包用空行隔开；</p></li><li><p>尽量不要使用匿名函数；</p></li><li><p>变量命名采用驼峰式；</p></li><li><p>对外暴露的变量或方法需要添加注释</p></li></ol>',2),o=[p];function n(s,r,d,_,c,g){return i(),e("div",null,o)}const m=a(t,[["render",n]]);export{f as __pageData,m as default};
